import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbBlockUiComponent, HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-block-ui-fullscreen',
  imports: [HbBlockUiComponent, HbButtonComponent],
  template: `
    <button hb-button (click)="block()" [hbDisabled]="busy()">Block screen (1.5s)</button>

    <hb-block-ui [hbBlocked]="busy()" hbFullScreen hbSpinner>
      <span hbBlockUiContent class="text-sm font-medium text-foreground">Cataloguing…</span>
    </hb-block-ui>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoBlockUiFullscreenComponent {
  protected readonly busy = signal(false);

  protected block(): void {
    this.busy.set(true);
    setTimeout(() => this.busy.set(false), 1500);
  }
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { provideIcons } from '@ng-icons/core';
import { phosphorLock } from '@ng-icons/phosphor-icons/regular';

import { HbBlockUiComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-block-ui-message',
  imports: [HbBlockUiComponent],
  providers: [provideIcons({ phosphorLock })],
  template: `
    <hb-block-ui
      [hbBlocked]="true"
      hbIcon="phosphorLock"
      class="w-full max-w-sm rounded-lg border border-border"
    >
      <span hbBlockUiContent class="text-sm font-medium text-foreground">Archived — read only</span>

      <div class="flex flex-col gap-1 p-6">
        <h3 class="font-medium">October in the Black Forest</h3>
        <p class="text-sm text-muted-foreground">
          This photo was archived and can no longer be edited.
        </p>
      </div>
    </hb-block-ui>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoBlockUiMessageComponent {}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbBlockUiComponent, HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-block-ui-spinner',
  imports: [HbBlockUiComponent, HbButtonComponent],
  template: `
    <div class="w-full max-w-sm">
      <hb-block-ui [hbBlocked]="loading()" hbSpinner class="rounded-lg border border-border">
        <div class="flex flex-col gap-1 p-6">
          <h3 class="font-medium">Autumn walk</h3>
          <p class="text-sm text-muted-foreground">Oak leaves along the river — Freiburg.</p>
          <p class="text-sm text-muted-foreground">Taken Nov 3, 2026 · Black Forest.</p>
        </div>
      </hb-block-ui>

      <button hb-button hbSize="sm" class="mt-3" [hbDisabled]="loading()" (click)="reload()">
        Reload
      </button>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoBlockUiSpinnerComponent {
  protected readonly loading = signal(false);

  protected reload(): void {
    this.loading.set(true);
    setTimeout(() => this.loading.set(false), 1500);
  }
}
